INSERT INTO ARTCERT ( req_seq, auth_type, cipher_time, res_seq, name, birth_date, gender, nationa_info, dup_info, conn_info, mobile_co, mobile_no, err_code, err_msg, chg_date )
             VALUES ( #{reqSeq}
                    , #{authType}
                    , #{cipherTime}
                    , #{resSeq}
                    , #{name}
                    , #{birthDate}
                    , #{gender}
                    , #{nationaInfo}
                    , #{dupInfo}
                    , #{connInfo}
                    , #{mobileCo}
                    , #{mobileNo}
                    , #{errCode}
                    , #{errMsg}
                    , NOW()
                    )
